// ============================================
// Genera queries de búsqueda para Google Maps
// Rubros y ciudades de Uruguay (expandible a LATAM)
// ============================================

const rubros = [
  'restaurante',
  'peluquería',
  'barbería',
  'clínica dental',
  'estudio contable',
  'inmobiliaria',
  'veterinaria',
  'gimnasio',
  'taller mecánico',
  'óptica',
  'centro de estética',
  'spa',
  'panadería',
  'ferretería',
  'hotel',
  'lavadero de autos',
  'florería',
  'academia',
  'estudio de yoga',
  'consultorio médico'
];

const ciudades = [
  { nombre: 'Montevideo', lat: -34.9011, lng: -56.1645, pais: 'Uruguay' },
  { nombre: 'Punta del Este', lat: -34.9667, lng: -54.9500, pais: 'Uruguay' },
  { nombre: 'Colonia del Sacramento', lat: -34.4626, lng: -57.8400, pais: 'Uruguay' },
  { nombre: 'Salto', lat: -31.3833, lng: -57.9667, pais: 'Uruguay' },
  { nombre: 'Paysandú', lat: -32.3214, lng: -58.0756, pais: 'Uruguay' },
  { nombre: 'Maldonado', lat: -34.9000, lng: -54.9500, pais: 'Uruguay' },
  { nombre: 'Rivera', lat: -30.9050, lng: -55.5506, pais: 'Uruguay' }
];

// Seleccionar aleatoriamente 3-5 combinaciones para hoy
// (no queremos hacer 140 búsquedas de golpe)
const queries = [];
const maxQueriesHoy = 5;

const shuffled = [];
for (const ciudad of ciudades) {
  for (const rubro of rubros) {
    shuffled.push({ ciudad, rubro });
  }
}

// Shuffle Fisher-Yates
for (let i = shuffled.length - 1; i > 0; i--) {
  const j = Math.floor(Math.random() * (i + 1));
  [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
}

const seleccion = shuffled.slice(0, maxQueriesHoy);

for (const { ciudad, rubro } of seleccion) {
  queries.push({
    json: {
      query: `${rubro} en ${ciudad.nombre}`,
      rubro: rubro,
      ciudad: ciudad.nombre,
      pais: ciudad.pais,
      coordinates: `@${ciudad.lat},${ciudad.lng},14z`,
      lat: ciudad.lat,
      lng: ciudad.lng
    }
  });
}

return queries;

// ============================================
// Parsea resultados de SerpAPI Google Maps
// Extrae datos de comercios y normaliza teléfonos
// ============================================

const input = $input.first().json;
const results = input.local_results || [];
const searchMeta = $('Procesar por Lotes').first().json;

const leads = [];

for (const r of results) {
  // Saltar si no tiene teléfono (no podemos contactar por WA)
  if (!r.phone) continue;

  // Normalizar teléfono a formato internacional Uruguay (+598)
  let phone = r.phone.replace(/[\s\-\(\)\.]/g, '');

  // Si empieza con 0, quitar el 0 y agregar +598
  if (phone.startsWith('0')) {
    phone = '+598' + phone.substring(1);
  }
  // Si no empieza con +, agregar +598
  else if (!phone.startsWith('+')) {
    if (phone.startsWith('598')) {
      phone = '+' + phone;
    } else {
      phone = '+598' + phone;
    }
  }

  // Solo números válidos de Uruguay (9-10 dígitos después del +598)
  const digits = phone.replace('+598', '');
  if (digits.length < 7 || digits.length > 10) continue;

  // Formatear para WhatsApp (sin + ni espacios)
  const whatsapp = phone.replace('+', '');

  leads.push({
    json: {
      nombre: r.title || 'Sin nombre',
      rubro: searchMeta.rubro || r.type || 'comercio',
      ciudad: searchMeta.ciudad || '',
      pais: searchMeta.pais || 'Uruguay',
      whatsapp: whatsapp,
      website: r.website || '',
      direccion: r.address || '',
      rating: r.rating || 0,
      reviews_count: r.reviews || 0,
      origen: 'google_maps',
      thumbnail: r.thumbnail || ''
    }
  });
}

if (leads.length === 0) {
  return [{ json: { skip: true, message: 'No se encontraron resultados con teléfono' } }];
}

return leads;

// ============================================
// Calcula score de prospecto basado en criterios
// Mayor score = mejor candidato para ofrecer servicios
// ============================================

const lead = $json;
let score = 50; // Base

// +20 si tiene website (podemos evaluar si es obsoleta)
if (lead.website && lead.website.length > 0) {
  score += 10;
}

// +15 si NO tiene website (necesitan presencia digital)
if (!lead.website || lead.website.length === 0) {
  score += 15;
}

// Rating bajo = posible negocio que necesita ayuda
if (lead.rating > 0 && lead.rating < 4.0) {
  score += 10;
}

// Pocas reviews = negocio chico, buen target
if (lead.reviews_count > 0 && lead.reviews_count < 50) {
  score += 10;
}

// Muchas reviews = negocio establecido, puede pagar
if (lead.reviews_count >= 50) {
  score += 5;
}

// Rubros con mayor necesidad de automatización
const rubrosAltos = ['restaurante', 'peluquería', 'barbería', 'clínica dental', 
  'veterinaria', 'centro de estética', 'spa', 'gimnasio', 'hotel'];
if (rubrosAltos.some(r => lead.rubro.toLowerCase().includes(r))) {
  score += 15;
}

// Cap at 100
score = Math.min(score, 100);

return {
  json: {
    ...lead,
    score_prospecto: score
  }
};
